import { useEffect, useState } from 'react';
import './App.css';
import credenciales from './componentes/credenciales';

function App() {
  const [data, setData] = useState([])
  useEffect(()=>{
    fetch('http://localhost:8081/usuarios')
    .then(res => res.json())
    .then(data => setData(data))
    .catch(err => console.log(err));
  },[])
  return (
    
    <div className="App">
      credenciales
      <table>
        <thead>
          <th>Usuario</th>
          <th>Contraseña</th>
        </thead>
      </table>
      <tbody>
        {data.map((d, i) => (
          <tr key={i}>
            <td>{d.correo}</td>
            <td>{d.contraseña}</td>
          </tr>
        ))}
      </tbody>
    </div>
  );
}

export default App;
